package com.gdxsim;

import com.badlogic.gdx.Gdx;
import com.badlogic.gdx.backends.headless.HeadlessApplication;
import com.badlogic.gdx.backends.headless.HeadlessApplicationConfiguration;

public class Main {

    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: gdx-sim <config-path> <output-path>");
            System.exit(1);
        }

        String configPath = args[0];
        String outputPath = args[1];

        HeadlessApplicationConfiguration config = new HeadlessApplicationConfiguration();
        // Run as fast as possible, not throttled by wall-clock pacing
        config.updatesPerSecond = 0;

        SimulationListener listener = new SimulationListener(configPath, outputPath);
        HeadlessApplication app = new HeadlessApplication(listener, config);

        // Gdx.app.exit() is asynchronous — it posts a Runnable that flips
        // a running flag and triggers pause() + dispose().  We must join
        // the main loop thread so the JVM doesn't exit before dispose()
        // has flushed the output file.
        try {
            app.getApplicationLogger().debug("Simulation", "Waiting for main loop to finish...");
            // The headless backend runs on the calling thread, so after
            // HeadlessApplication construction, the main loop is already
            // running synchronously.  When it returns, dispose() has been
            // called and the file has been flushed.
        } catch (Exception e) {
            e.printStackTrace();
            System.exit(1);
        }

        // The HeadlessApplication runs its main loop on the calling thread,
        // so by the time the constructor returns, the simulation is done.
        // No need for an explicit join — the constructor blocks until exit.
        System.exit(0);
    }
}

